using Microsoft.EntityFrameworkCore;
class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        // EF9: HasIndex throws for Cosmos entities — removed.
        // Cosmos indexing is managed via the container's indexing policy.

        modelBuilder.Entity<Blog>(b =>
        {
            // EF9: Default discriminator property renamed from "Discriminator" to "$type".
            // Preserve old name so existing documents remain readable.
            b.HasDiscriminator<string>("Discriminator");

            // EF9: id no longer includes discriminator prefix (was "Blog|1", now "1").
            // Preserve old format so existing documents are found by FindAsync/point-reads.
            b.HasRootDiscriminatorInJsonId(true);
        });
    }
}
class Blog { public string Id { get; set; } public string Name { get; set; } }

